INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Asesmen Sekolah & WASH', '2019', 'Melakukan asesmen komprehensif di berbagai sekolah di Kecamatan Sulamu, Kabupaten Kupang. Asesmen ini difokuskan pada evaluasi layanan pendidikan dasar serta infrastruktur Water, Sanitation, and Hygiene (WASH). Hasil asesmen ini menjadi landasan untuk program intervensi selanjutnya guna meningkatkan kualitas kesehatan dan pendidikan anak-anak di wilayah tersebut. 
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Pendampingan TAWA Semesta', '2019-2020', 'Program pendampingan berkelanjutan untuk LSM TAWA Semesta di Makasar. Kami memfasilitasi pengembangan rencana strategis yang berfokus pada program penggalangan dana yang efektif serta inisiatif ekonomi berkelanjutan. Tujuannya adalah untuk memperkuat kapasitas kelembagaan mereka agar dapat memberikan dampak yang lebih luas.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Distribusi Perlengkapan Sekolah', '2019', 'Bekerja sama dengan mitra strategis kami, CHARIS National Academy dan Sumba Integrated Development (SID), program ini berhasil mendistribusikan perlengkapan sekolah yang sangat dibutuhkan oleh 20 anak di Desa Wanggabewa, Kecamatan Sumba Timur. Langkah ini diambil untuk memastikan anak-anak memiliki akses ke fasilitas belajar yang memadai.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Pengembangan Anak Muda', 'Juli - Oktober 2020', 'Fasilitasi kegiatan pengembangan kapasitas diri yang menargetkan 20 pemuda di Kota Kupang. Program yang didanai secara mandiri ini bertujuan untuk membekali generasi muda dengan keterampilan abad ke-21, kepemimpinan, serta kewirausahaan.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Suplementasi WIFA', 'Okt 2020 - Mar 2021', 'Rangkaian lokakarya orientasi dan peningkatan kapasitas untuk Program Suplementasi Weekly Iron and Folic Acid (WIFA) bagi remaja putri dan wanita usia subur di Kabupaten TTU dan Kupang. Program ini didukung oleh Nutrition International untuk menanggulangi masalah anemia di wilayah tersebut.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Kapasitas Eks Pekerja Migran', 'Feb - Apr 2021', 'Berkolaborasi dengan Sumba Integrated Development (SID) dan didukung oleh International Organization for Migration (IOM), kami mengadakan program peningkatan kapasitas ekonomi dan psikososial bagi para eks pekerja migran di Kabupaten Sumba Barat dan Sumba Barat Daya. Program ini membantu reintegrasi mereka kembali ke masyarakat secara produktif.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Respon Bencana Seroja', 'Maret - April 2021', 'Tindakan cepat tanggap darurat dalam merespon badai siklon tropis Seroja yang melanda Kabupaten dan Kota Kupang. Kami bergerak secara independen serta berkoordinasi dengan mitra seperti TAWA Semesta dan IBU Foundation untuk mendistribusikan bantuan logistik, perlengkapan higienis, dan dukungan psikososial kepada korban terdampak.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Pelatihan Menulis Kreatif', 'Agustus 2021', 'Program pelatihan daring yang terbuka untuk masyarakat luas di Nusa Tenggara Timur, berfokus pada pengembangan teknik menulis kreatif. Tujuan utama program ini adalah meningkatkan minat literasi masyarakat sekaligus mendokumentasikan kearifan lokal melalui tulisan.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Proyek BISA (Nutrisi)', 'Juni - November 2021', 'Proyek BISA (Better Investment for Stunting Alleviation) berfokus pada rapat perencanaan mikro serta penguatan mekanisme rantai pasok komoditas nutrisi esensial di tingkat kabupaten (TTU dan Kupang). Hal ini bertujuan memastikan ketersediaan suplemen gizi bagi ibu hamil dan balita.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Proyek Lii Marapu', 'Agt 2021 - Agt 2023', 'Sebuah program komprehensif yang didanai oleh VOICE untuk mendukung pemberdayaan dan perlindungan hak-hak Komunitas Adat Marapu di Sumba Timur. Proyek ini mengintervensi dari sisi pelestarian budaya, advokasi hak sipil, hingga penguatan ekonomi adat secara berkelanjutan.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Dukungan Lii Marapu', '2022 - 2023', 'Program advokasi dan dukungan teknis lanjutan yang terselenggara atas sinergi dengan Direktorat Kepercayaan terhadap Tuhan YME dan Masyarakat Adat (Kemendikbudristek RI). Langkah ini guna mengukuhkan eksistensi kebudayaan Lii Marapu di kancah nasional.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Supportive Supervision BISA', 'Sept - Des 2023', 'Pelaksanaan supervisi fasilitatif di berbagai Puskesmas dan sekolah-sekolah untuk memastikan berjalannya program gizi ibu dan anak, serta suplementasi Weekly Iron Folic Acid (WIFA) secara efektif dan efisien. Program ini merupakan kemitraan strategis dengan Nutrition International.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Training VAS Supply Chain', 'Okt - Des 2023', 'Penyelenggaraan pelatihan intensif terkait Manajemen Terpadu Suplementasi Vitamin A (VAS) dan Manajemen Rantai Pasok Kapsul Vitamin A (VAC). Pelatihan ini ditujukan kepada tenaga gizi Puskesmas untuk meminimalisasi risiko stock-out dan memastikan cakupan distribusi optimal kepada balita.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Dokumentasi Karya Para Maestro Kepercayaan dan Kebudayaan Jingitiu di Kabupaten Sabu Raijua.', 'Nov 2023 - Sept 2024', 'Proyek pendokumentasian secara mendalam karya-karya lisan, ritual, dan pengetahuan ekologis para Maestro aliran kepercayaan dan kebudayaan Jingitiu di Kabupaten Sabu Raijua. Proyek strategis ini merupakan mandat dari Kemendikbudristek dan LPDP dalam upaya preservasi warisan budaya tak benda.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Kurikulum Operasional PAUD', 'Sept 2024 - Okt 2025', 'Pengembangan Kurikulum Operasional Satuan PAUD (KOSP) yang berkualitas, inklusif, serta disesuaikan dengan konteks sosial budaya lokal di Kabupaten Kupang. Program ini menargetkan penguatan kapasitas kepala sekolah dan tenaga pendidik PAUD guna merancang pembelajaran yang berpusat pada anak.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('PELITA PAUD', 'April 2026 - Maret 2029', 'Program komprehensif jangka panjang yang menitikberatkan pada peningkatan kualitas pembelajaran di satuan PAUD, sekaligus membangun sistem kemitraan yang kuat antara pihak pendidik dan orang tua. Hal ini untuk menjamin keselarasan stimulasi perkembangan anak di sekolah dan di rumah.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Innovation Lab 2025', '2025', 'Keterlibatan proaktif tim Marungga Foundation dalam wadah Innovation Lab 2025. Inisiatif ini dirancang untuk mendongkrak kapasitas kelembagaan, merumuskan strategi inovasi, dan mengeksplorasi model-model intervensi sosial terbaru guna menjawab tantangan kemanusiaan masa depan.
INSERT INTO public.marungga_programs (title, year, description, image_url) VALUES ('Ketahanan Pangan & Ternak', 'Okt 2022 - Sekarang', 'Model bisnis sosial yang mendayagunakan aset organisasi melalui program penanaman pepaya skala menengah dan pemeliharaan ternak sapi potong. Program yang diinisiasi dari kas mandiri lembaga ini berjalan atas kemitraan dengan kelompok masyarakat lokal, dan keuntungannya dikembalikan sebagai dana silang untuk program-program sosial yayasan.
